// ESM wrapper for mermaid IIFE bundle (offline-capable)
// Load as classic script so var declarations become globals.
const load = () => new Promise((resolve, reject) => {
  if (globalThis.mermaid) { resolve(); return; }
  const script = document.createElement('script');
  script.src = '/lib/mermaid.min.js';
  script.onload = () => resolve();
  script.onerror = (e) => reject(new Error('Failed to load mermaid.min.js'));
  document.head.appendChild(script);
});
await load();
const mermaid = globalThis.mermaid;
export default mermaid;
